import requests
import json
from concurrent.futures import ThreadPoolExecutor, as_completed

# 定义API端点
APIS = {
    "integrations": {"url": "http://localhost:34051/config/integrations", "method": "GET"},
    "helpdesk_tickets": {"url": "http://localhost:59599/helpdesk/tickets", "method": "GET"},
    "inventory_products": {"url": "http://localhost:33745/inventory/products", "method": "GET"},
