        if api_info["method"] == "GET":
            response = requests.get(api_info["url"], timeout=30)
        else:
            response = requests.post(api_info["url"], timeout=30)
        return {name: {"status": response.status_code, "data": response.json()}}
    except Exception as e:
        return {name: {"status": "error", "error": str(e)}}

# 并行调用所有API
